namespace fs = std::filesystem;

using i64 = std::int64_t;

/**
 * @brief Contador simple de accesos a disco.
 *
 * Cada lectura o escritura de un bloque de tamaño B incrementa uno de los
 * contadores.
 */
struct DiskStats {
    std::uint64_t reads = 0;
    std::uint64_t writes = 0;
};

/**
 * @brief Parámetros globales de ejecución.
 */
struct SortConfig {
    std::size_t block_bytes = 4096;
    std::size_t memory_bytes = 4u * 1024u * 1024u;
    std::uint64_t seed = 0xC0FFEEULL;
};

/**
 * @brief Devuelve la cantidad de elementos de 64 bits que caben en un bloque.
 */
static std::size_t block_elements(const SortConfig &cfg) {
    return cfg.block_bytes / sizeof(i64);
}

/**
 * @brief Calcula el número de bloques lógicos necesarios para almacenar n elementos.
 */
static std::size_t logical_blocks(std::size_t n, std::size_t elems_per_block) {
    return (n + elems_per_block - 1) / elems_per_block;
}

/**
 * @brief Construye la ruta del archivo auxiliar que guarda el tamaño lógico.
 */
static std::string count_sidecar_path(const std::string &path) {
    return path + ".count";
}

/**
 * @brief Guarda el tamaño lógico de un archivo binario en un archivo auxiliar.
 */
static void write_count_sidecar(const std::string &path, std::size_t count) {
    std::ofstream out(count_sidecar_path(path), std::ios::trunc);
    if (!out) {
        throw std::runtime_error("No se pudo escribir sidecar de tamaño: " + path);
    }
    out << count << '\n';
}

/**
 * @brief Intenta leer el tamaño lógico desde un archivo auxiliar.
 */
static std::optional<std::size_t> read_count_sidecar(const std::string &path) {
    std::ifstream in(count_sidecar_path(path));
    if (!in) {
        return std::nullopt;
    }
    std::size_t count = 0;
    in >> count;
    if (!in) {
        throw std::runtime_error("Sidecar de tamaño inválido: " + path);
    }
    return count;
}

/**
 * @brief Obtiene el tamaño lógico de un archivo binario.
 *
 * Si existe un sidecar, se usa ese valor. En caso contrario, se infiere desde
 * el tamaño físico del archivo.
 */
static std::size_t resolve_count(const std::string &path) {
    if (auto sidecar = read_count_sidecar(path)) {
        return *sidecar;
    }
    auto size = fs::file_size(path);
    if (size % sizeof(i64) != 0) {
        throw std::runtime_error("El archivo no es múltiplo de 64 bits: " + path);
    }
    return static_cast<std::size_t>(size / sizeof(i64));
}

/**
 * @brief Crea un archivo temporal único y devuelve su ruta.
 */
static std::string make_temp_path(const std::string &prefix = "externalsort_") {
    fs::path dir = fs::temp_directory_path();
    std::string tmpl = (dir / (prefix + "XXXXXX")).string();
    std::vector<char> buf(tmpl.begin(), tmpl.end());
    buf.push_back('\0');
    int fd = mkstemp(buf.data());
    if (fd == -1) {
        throw std::runtime_error("No se pudo crear archivo temporal");
    }
    std::fclose(fdopen(fd, "w"));
    return std::string(buf.data());
}

/**
 * @brief Elimina un archivo si existe.
 */
static void remove_if_exists(const std::string &path) {
    std::error_code ec;
    fs::remove(path, ec);
}

/**
 * @brief Lectura secuencial de elementos basada en bloques.
 */
class BlockReader {
  public:
    /**
     * @brief Abre un archivo binario para lectura secuencial.
     * @param path Ruta del archivo.
     * @param logical_count Cantidad lógica de elementos a exponer.
     * @param cfg Parámetros globales.
     * @param stats Contador de accesos a disco.
     */
    BlockReader(const std::string &path, std::size_t logical_count,
                const SortConfig &cfg, DiskStats *stats)
        : fp_(std::fopen(path.c_str(), "rb")),
          logical_count_(logical_count),
          elems_per_block_(block_elements(cfg)),
          block_bytes_(cfg.block_bytes), stats_(stats), buffer_(elems_per_block_) {
        if (!fp_) {
            throw std::runtime_error("No se pudo abrir para lectura: " + path);
        }
    }

    /**
     * @brief Destructor: cierra el archivo.
     */
    ~BlockReader() {
        if (fp_) {
            std::fclose(fp_);
        }
    }

    BlockReader(const BlockReader &) = delete;
    BlockReader &operator=(const BlockReader &) = delete;

    /**
     * @brief Obtiene el siguiente elemento lógico.
     * @param value Salida con el siguiente entero.
     * @return true si existe un elemento disponible, false en caso contrario.
     */
    bool next(i64 &value) {
        if (consumed_ >= logical_count_) {
            return false;
        }
        if (buffer_pos_ >= buffer_size_) {
            refill();
        }
        value = buffer_[buffer_pos_++];
        ++consumed_;
        return true;
    }

  private:
    /**
     * @brief Lee el siguiente bloque desde disco.
     */
    void refill() {
        if (consumed_ >= logical_count_) {
            buffer_size_ = 0;
            buffer_pos_ = 0;
            return;
        }
        const std::size_t remaining = logical_count_ - consumed_;
        buffer_size_ = std::min(elems_per_block_, remaining);
        const std::size_t read_count = std::fread(buffer_.data(), sizeof(i64), elems_per_block_, fp_);
        if (read_count != elems_per_block_) {
            throw std::runtime_error("Lectura incompleta de bloque");
        }
        if (stats_) {
            ++stats_->reads;
        }
        buffer_pos_ = 0;
    }

    FILE *fp_ = nullptr;
    std::size_t logical_count_ = 0;
    std::size_t elems_per_block_ = 0;
    std::size_t block_bytes_ = 0;
    DiskStats *stats_ = nullptr;
    std::vector<i64> buffer_;
    std::size_t buffer_pos_ = 0;
    std::size_t buffer_size_ = 0;
    std::size_t consumed_ = 0;
};

/**
 * @brief Escritura secuencial de elementos basada en bloques.
 */
class BlockWriter {
  public:
    /**
     * @brief Abre un archivo binario para escritura secuencial.
     * @param path Ruta del archivo.
     * @param cfg Parámetros globales.
     * @param stats Contador de accesos a disco.
     */
    BlockWriter(const std::string &path, const SortConfig &cfg, DiskStats *stats)
        : fp_(std::fopen(path.c_str(), "wb")),
          elems_per_block_(block_elements(cfg)),
          block_bytes_(cfg.block_bytes), stats_(stats), buffer_(elems_per_block_) {
        if (!fp_) {
            throw std::runtime_error("No se pudo abrir para escritura: " + path);
        }
    }

    /**
     * @brief Destructor: vacía el buffer y cierra el archivo.
     */
    ~BlockWriter() {
        try {
            close();
        } catch (...) {
        }
    }

    BlockWriter(const BlockWriter &) = delete;
    BlockWriter &operator=(const BlockWriter &) = delete;

    /**
     * @brief Agrega un elemento al buffer de salida.
     */
    void push(i64 value) {
        buffer_[filled_++] = value;
        ++logical_written_;
        if (filled_ == elems_per_block_) {
            flush_full_block();
        }
    }

    /**
     * @brief Cierra el archivo, escribiendo el último bloque con padding.
     */
    void close() {
        if (!fp_) {
            return;
        }
        if (filled_ > 0) {
            pad_and_flush();
        }
        std::fclose(fp_);
        fp_ = nullptr;
    }

    /**
     * @brief Cantidad lógica de elementos escritos.
     */
    std::size_t logical_written() const {
        return logical_written_;
    }

  private:
    /**
     * @brief Escribe un bloque completo.
     */
    void flush_full_block() {
        const std::size_t written = std::fwrite(buffer_.data(), sizeof(i64), elems_per_block_, fp_);
        if (written != elems_per_block_) {
            throw std::runtime_error("Escritura incompleta de bloque");
        }
        if (stats_) {
            ++stats_->writes;
        }
        filled_ = 0;
    }

    /**
     * @brief Completa el bloque parcial con valores centinela y lo escribe.
     */
    void pad_and_flush() {
        std::fill(buffer_.begin() + static_cast<std::ptrdiff_t>(filled_), buffer_.end(),
                  std::numeric_limits<i64>::max());
        flush_full_block();
    }

    FILE *fp_ = nullptr;
    std::size_t elems_per_block_ = 0;
    std::size_t block_bytes_ = 0;
    DiskStats *stats_ = nullptr;
    std::vector<i64> buffer_;
    std::size_t filled_ = 0;
    std::size_t logical_written_ = 0;
};

/**
 * @brief Carga un archivo completo a memoria principal.
 * @param path Ruta del archivo.
 * @param logical_count Cantidad de elementos a leer.
 * @param cfg Parámetros globales.
 * @param stats Contador de disco.
 * @return Vector con los elementos leídos.
 */
static std::vector<i64> load_file(const std::string &path, std::size_t logical_count,
                                  const SortConfig &cfg, DiskStats *stats) {
    std::vector<i64> data;
    data.reserve(logical_count);
    BlockReader reader(path, logical_count, cfg, stats);
    i64 value;
    while (reader.next(value)) {
        data.push_back(value);
    }
    return data;
}

/**
 * @brief Guarda un vector de elementos en un archivo binario por bloques.
 */
static void save_file(const std::string &path, const std::vector<i64> &data,
                      const SortConfig &cfg, DiskStats *stats) {
    BlockWriter writer(path, cfg, stats);
    for (i64 value : data) {
        writer.push(value);
    }
    writer.close();
    write_count_sidecar(path, data.size());
}

/**
 * @brief Copia un archivo lógico a otro respetando el tamaño dado.
 */
static void copy_file(const std::string &in, std::size_t count, const std::string &out,
                      const SortConfig &cfg, DiskStats *stats) {
    BlockReader reader(in, count, cfg, stats);
    BlockWriter writer(out, cfg, stats);
    i64 value;
    while (reader.next(value)) {
        writer.push(value);
    }
    writer.close();
    write_count_sidecar(out, count);
}

/**
 * @brief Genera una secuencia aleatoria de enteros de 64 bits y la guarda en disco.
 */
static void generate_random_file(const std::string &path, std::size_t count,
                                 std::uint64_t seed, const SortConfig &cfg) {
    std::mt19937_64 rng(seed);
    std::uniform_int_distribution<i64> dist(std::numeric_limits<i64>::min(),
                                            std::numeric_limits<i64>::max());
    std::vector<i64> data;
    data.reserve(count);
    for (std::size_t i = 0; i < count; ++i) {
        data.push_back(dist(rng));
    }
    DiskStats dummy;
    save_file(path, data, cfg, &dummy);
}

/**
 * @brief Selecciona pivotes aleatorios desde un bloque del archivo.
 *
 * Si el bloque leído no contiene suficientes elementos válidos, se permite
 * re-muestreo con reemplazo para mantener exactamente a-1 pivotes.
 */
static std::vector<i64> choose_pivots(const std::string &path, std::size_t logical_count,
                                      std::size_t arity, const SortConfig &cfg,
                                      std::mt19937_64 &rng, DiskStats *stats) {
    const std::size_t elems_per_block = block_elements(cfg);
    const std::size_t blocks = logical_blocks(logical_count, elems_per_block);
    if (blocks == 0) {
        return {};
    }
    std::uniform_int_distribution<std::size_t> block_dist(0, blocks - 1);

    std::vector<i64> block(elems_per_block);
    std::size_t valid = 0;
    std::size_t block_idx = 0;
    for (int attempts = 0; attempts < 32; ++attempts) {
        block_idx = block_dist(rng);
        valid = std::min(elems_per_block, logical_count - block_idx * elems_per_block);
        FILE *fp = std::fopen(path.c_str(), "rb");
        if (!fp) {
            throw std::runtime_error("No se pudo abrir archivo para elegir pivotes: " + path);
        }
        if (std::fseek(fp, static_cast<long>(block_idx * cfg.block_bytes), SEEK_SET) != 0) {
            std::fclose(fp);
            throw std::runtime_error("No se pudo posicionar archivo para pivotes");
        }
        const std::size_t read_count = std::fread(block.data(), sizeof(i64), elems_per_block, fp);
        std::fclose(fp);
        if (read_count != elems_per_block) {
            throw std::runtime_error("Lectura incompleta al elegir pivotes");
        }
        if (stats) {
            ++stats->reads;
        }
        if (valid > 0) {
            break;
        }
    }

    const std::size_t needed = (arity > 0) ? arity - 1 : 0;
    std::vector<i64> pivots;
    pivots.reserve(needed);

    if (needed == 0) {
        return pivots;
    }

    // Muestreo sin reemplazo mientras sea posible.
    std::vector<std::size_t> idx(valid);
    std::iota(idx.begin(), idx.end(), 0);
    std::shuffle(idx.begin(), idx.end(), rng);
    const std::size_t take = std::min(needed, valid);
    for (std::size_t i = 0; i < take; ++i) {
        pivots.push_back(block[idx[i]]);
    }
    // Completar con reemplazo si se pidieron más pivotes que elementos válidos.
    std::uniform_int_distribution<std::size_t> valid_dist(0, valid > 0 ? valid - 1 : 0);
    while (pivots.size() < needed && valid > 0) {
        pivots.push_back(block[valid_dist(rng)]);
    }
    std::sort(pivots.begin(), pivots.end());
    return pivots;
}

/**
 * @brief Particiona un archivo en a subarchivos usando pivotes dados.
 */
static std::vector<std::pair<std::string, std::size_t>> partition_by_pivots(
    const std::string &input, std::size_t logical_count, const std::vector<i64> &pivots,
    const SortConfig &cfg, DiskStats *stats) {
    const std::size_t arity = pivots.size() + 1;
    std::vector<std::string> paths(arity);
    std::vector<std::unique_ptr<BlockWriter>> writers;
    writers.reserve(arity);
    std::vector<std::size_t> counts(arity, 0);

    for (std::size_t i = 0; i < arity; ++i) {
        paths[i] = make_temp_path("qs_part_");
        writers.emplace_back(std::make_unique<BlockWriter>(paths[i], cfg, stats));
    }

    BlockReader reader(input, logical_count, cfg, stats);
    i64 value;
    while (reader.next(value)) {
        const auto it = std::upper_bound(pivots.begin(), pivots.end(), value);
        const std::size_t bucket = static_cast<std::size_t>(std::distance(pivots.begin(), it));
        writers[bucket]->push(value);
        ++counts[bucket];
    }

    for (auto &w : writers) {
        w->close();
    }

    std::vector<std::pair<std::string, std::size_t>> parts;
    parts.reserve(arity);
    for (std::size_t i = 0; i < arity; ++i) {
        write_count_sidecar(paths[i], counts[i]);
        parts.emplace_back(paths[i], counts[i]);
    }
    return parts;
}

/**
 * @brief Divide un archivo en a subarchivos de forma contigua.
 */
static std::vector<std::pair<std::string, std::size_t>> partition_contiguous(
    const std::string &input, std::size_t logical_count, std::size_t arity,
    const SortConfig &cfg, DiskStats *stats) {
    std::vector<std::pair<std::string, std::size_t>> parts;
    parts.reserve(arity);
    const std::size_t base = logical_count / arity;
    const std::size_t rem = logical_count % arity;

    BlockReader reader(input, logical_count, cfg, stats);
    i64 value;
    for (std::size_t i = 0; i < arity; ++i) {
        const std::size_t target = base + (i < rem ? 1 : 0);
        std::string path = make_temp_path("ms_part_");
        BlockWriter writer(path, cfg, stats);
        for (std::size_t j = 0; j < target; ++j) {
            if (!reader.next(value)) {
                throw std::runtime_error("Partición incompleta en mergesort");
            }
            writer.push(value);
        }
        writer.close();
        write_count_sidecar(path, target);
        parts.emplace_back(path, target);
    }
    return parts;
}

/**
 * @brief Une múltiples archivos ya ordenados en un único archivo de salida.
 */
static void merge_sorted_files(const std::vector<std::pair<std::string, std::size_t>> &parts,
                               const std::string &output, const SortConfig &cfg,
                               DiskStats *stats) {
    struct Node {
        i64 value;
        std::size_t idx;
        bool operator>(const Node &other) const { return value > other.value; }
    };

    std::vector<std::unique_ptr<BlockReader>> readers;
    readers.reserve(parts.size());
    for (const auto &part : parts) {
        readers.emplace_back(std::make_unique<BlockReader>(part.first, part.second, cfg, stats));
    }

    BlockWriter writer(output, cfg, stats);
    std::priority_queue<Node, std::vector<Node>, std::greater<Node>> pq;
    for (std::size_t i = 0; i < readers.size(); ++i) {
        i64 value;
        if (readers[i]->next(value)) {
            pq.push(Node{value, i});
        }
    }

    while (!pq.empty()) {
        Node node = pq.top();
        pq.pop();
        writer.push(node.value);
        i64 next_value;
        if (readers[node.idx]->next(next_value)) {
            pq.push(Node{next_value, node.idx});
        }
    }

    writer.close();
}

/**
 * @brief Concatena archivos en orden en un único archivo.
 */
static void concatenate_files(const std::vector<std::pair<std::string, std::size_t>> &parts,
                              const std::string &output, const SortConfig &cfg,
                              DiskStats *stats) {
    std::vector<std::unique_ptr<BlockReader>> readers;
    readers.reserve(parts.size());
    for (const auto &part : parts) {
        readers.emplace_back(std::make_unique<BlockReader>(part.first, part.second, cfg, stats));
    }

    BlockWriter writer(output, cfg, stats);
    for (std::size_t i = 0; i < readers.size(); ++i) {
        i64 value;
        while (readers[i]->next(value)) {
            writer.push(value);
        }
    }
    writer.close();
}

/**
 * @brief Ordena un archivo usando mergesort externo.
 */
static void external_mergesort(const std::string &input, const std::string &output,
                               std::size_t logical_count, std::size_t arity,
                               const SortConfig &cfg, DiskStats *stats) {
    const std::size_t memory_elems = cfg.memory_bytes / sizeof(i64);
    if (logical_count <= memory_elems) {
        auto data = load_file(input, logical_count, cfg, stats);
        std::sort(data.begin(), data.end());
        save_file(output, data, cfg, stats);
        return;
    }

    auto parts = partition_contiguous(input, logical_count, arity, cfg, stats);
    std::vector<std::pair<std::string, std::size_t>> sorted_parts;
    sorted_parts.reserve(parts.size());
    for (const auto &part : parts) {
        std::string sorted_path = make_temp_path("ms_sorted_");
        external_mergesort(part.first, sorted_path, part.second, arity, cfg, stats);
        sorted_parts.emplace_back(sorted_path, part.second);
    }

    merge_sorted_files(sorted_parts, output, cfg, stats);

    for (const auto &part : parts) {
        remove_if_exists(part.first);
        remove_if_exists(count_sidecar_path(part.first));
    }
    for (const auto &part : sorted_parts) {
        remove_if_exists(part.first);
        remove_if_exists(count_sidecar_path(part.first));
    }
    write_count_sidecar(output, logical_count);
}

/**
 * @brief Ordena un archivo usando quicksort externo.
 */
static void external_quicksort(const std::string &input, const std::string &output,
                               std::size_t logical_count, std::size_t arity,
                               const SortConfig &cfg, DiskStats *stats,
                               std::mt19937_64 &rng) {
    const std::size_t memory_elems = cfg.memory_bytes / sizeof(i64);
    if (logical_count <= memory_elems) {
        auto data = load_file(input, logical_count, cfg, stats);
        std::sort(data.begin(), data.end());
        save_file(output, data, cfg, stats);
        return;
    }

    auto pivots = choose_pivots(input, logical_count, arity, cfg, rng, stats);
    auto parts = partition_by_pivots(input, logical_count, pivots, cfg, stats);

    std::vector<std::pair<std::string, std::size_t>> sorted_parts;
    sorted_parts.reserve(parts.size());
    for (const auto &part : parts) {
        std::string sorted_path = make_temp_path("qs_sorted_");
        external_quicksort(part.first, sorted_path, part.second, arity, cfg, stats, rng);
        sorted_parts.emplace_back(sorted_path, part.second);
    }

    concatenate_files(sorted_parts, output, cfg, stats);

    for (const auto &part : parts) {
        remove_if_exists(part.first);
        remove_if_exists(count_sidecar_path(part.first));
    }
    for (const auto &part : sorted_parts) {
        remove_if_exists(part.first);
        remove_if_exists(count_sidecar_path(part.first));
    }
    write_count_sidecar(output, logical_count);
}

/**
 * @brief Verifica si un archivo está ordenado no decrecientemente.
 */
static bool is_sorted_file(const std::string &path, std::size_t logical_count,
                           const SortConfig &cfg, DiskStats *stats) {
    BlockReader reader(path, logical_count, cfg, stats);
    if (logical_count == 0) {
        return true;
    }
    i64 prev = 0, value = 0;
    if (!reader.next(prev)) {
        return true;
    }
    while (reader.next(value)) {
        if (value < prev) {
            return false;
        }
        prev = value;
    }
    return true;
}

/**
 * @brief Calcula el tiempo en milisegundos de una función.
 */
template <class F>
static double measure_ms(F &&fn) {
    auto start = std::chrono::high_resolution_clock::now();
    fn();
    auto end = std::chrono::high_resolution_clock::now();
    return std::chrono::duration<double, std::milli>(end - start).count();
}

/**
 * @brief Estructura con un resultado de benchmark.
 */
struct BenchmarkRow {
    std::size_t size_bytes = 0;
    std::size_t instance = 0;
    std::string algorithm;
    std::size_t arity = 0;
    double time_ms = 0.0;
    std::uint64_t disk_accesses = 0;
};

/**
 * @brief Escribe un archivo CSV con los resultados.
 */
static void write_csv(const std::string &path, const std::vector<BenchmarkRow> &rows) {
    std::ofstream out(path, std::ios::trunc);
    if (!out) {
        throw std::runtime_error("No se pudo escribir CSV: " + path);
    }
    out << "size_bytes,instance,algorithm,arity,time_ms,disk_accesses\n";
    out << std::fixed << std::setprecision(3);
    for (const auto &r : rows) {
        out << r.size_bytes << ',' << r.instance << ',' << r.algorithm << ',' << r.arity << ','
            << r.time_ms << ',' << r.disk_accesses << '\n';
    }
}

/**
 * @brief Ejecuta una batería de experimentos para mergesort y quicksort.
 */
static void run_benchmark(const std::string &outdir, std::size_t arity,
                          const SortConfig &cfg) {
    fs::create_directories(outdir);
    const std::vector<std::size_t> sizes = {4u * 1024u * 1024u, 8u * 1024u * 1024u,
                                            12u * 1024u * 1024u, 16u * 1024u * 1024u};
    const std::size_t repetitions = 5;
    std::vector<BenchmarkRow> rows;
    std::uint64_t base_seed = cfg.seed;

    for (std::size_t size_bytes : sizes) {
        const std::size_t count = size_bytes / sizeof(i64);
        for (std::size_t rep = 0; rep < repetitions; ++rep) {
            const std::uint64_t seed = base_seed + size_bytes + rep * 1337ULL;
            fs::path input = fs::path(outdir) / ("data_" + std::to_string(size_bytes) + "_" + std::to_string(rep) + ".bin");
            generate_random_file(input.string(), count, seed, cfg);

            {
                DiskStats stats;
                fs::path output = fs::path(outdir) / ("merge_" + std::to_string(size_bytes) + "_" + std::to_string(rep) + ".bin");
                double ms = measure_ms([&] {
                    external_mergesort(input.string(), output.string(), count, arity, cfg, &stats);
                });
                if (!is_sorted_file(output.string(), count, cfg, nullptr)) {
                    throw std::runtime_error("Mergesort produjo salida no ordenada");
                }
                rows.push_back({size_bytes, rep, "mergesort", arity, ms, stats.reads + stats.writes});
                remove_if_exists(output.string());
                remove_if_exists(count_sidecar_path(output.string()));
            }

            {
                DiskStats stats;
                fs::path output = fs::path(outdir) / ("quick_" + std::to_string(size_bytes) + "_" + std::to_string(rep) + ".bin");
                std::mt19937_64 rng(seed ^ 0x9E3779B97F4A7C15ULL);
                double ms = measure_ms([&] {
                    external_quicksort(input.string(), output.string(), count, arity, cfg, &stats, rng);
                });
                if (!is_sorted_file(output.string(), count, cfg, nullptr)) {
                    throw std::runtime_error("Quicksort produjo salida no ordenada");
                }
                rows.push_back({size_bytes, rep, "quicksort", arity, ms, stats.reads + stats.writes});
                remove_if_exists(output.string());
                remove_if_exists(count_sidecar_path(output.string()));
            }

            remove_if_exists(input.string());
            remove_if_exists(count_sidecar_path(input.string()));
        }
    }

    write_csv((fs::path(outdir) / "results.csv").string(), rows);

    std::map<std::pair<std::string, std::size_t>, std::pair<double, double>> agg;
    std::map<std::pair<std::string, std::size_t>, std::size_t> cnt;
    for (const auto &r : rows) {
        auto key = std::make_pair(r.algorithm, r.size_bytes);
        agg[key].first += r.time_ms;
        agg[key].second += static_cast<double>(r.disk_accesses);
        cnt[key] += 1;
    }

    std::ofstream summary((fs::path(outdir) / "summary.csv").string(), std::ios::trunc);
    summary << "algorithm,size_bytes,avg_time_ms,avg_disk_accesses\n";
    summary << std::fixed << std::setprecision(3);
    for (const auto &kv : agg) {
        const auto &key = kv.first;
        const auto &sum = kv.second;
        const std::size_t c = cnt[key];
        summary << key.first << ',' << key.second << ',' << (sum.first / c) << ','
                << (sum.second / c) << '\n';
    }
}

/**
 * @brief Busca la mejor aridad para mergesort en un rango dado.
 *
 * La implementación realiza barrido exhaustivo, porque el costo no es
 * necesariamente monótono con respecto a a.
 */
static std::size_t search_best_arity(const std::string &input, std::size_t logical_count,
                                     std::size_t min_a, std::size_t max_a,
                                     const SortConfig &cfg) {
    if (min_a < 2) {
        min_a = 2;
    }
    const std::size_t capped_max = std::min(max_a, block_elements(cfg));
    if (min_a > capped_max) {
        throw std::runtime_error("Rango de aridad inválido");
    }

    std::size_t best_a = min_a;
    double best_ms = std::numeric_limits<double>::infinity();
    for (std::size_t a = min_a; a <= capped_max; ++a) {
        DiskStats stats;
        std::string out = make_temp_path("arity_test_");
        double ms = measure_ms([&] {
            external_mergesort(input, out, logical_count, a, cfg, &stats);
        });
        if (ms < best_ms) {
            best_ms = ms;
            best_a = a;
        }
        remove_if_exists(out);
        remove_if_exists(count_sidecar_path(out));
    }
    return best_a;
}

/**
 * @brief Imprime instrucciones de uso.
 */
static void print_usage() {
    std::cout << "Uso:\n"
              << "  externalsort generate <archivo.bin> <cantidad> [seed]\n"
              << "  externalsort mergesort <entrada.bin> <salida.bin> <aridad> [cantidad]\n"
              << "  externalsort quicksort <entrada.bin> <salida.bin> <aridad> [cantidad]\n"
              << "  externalsort benchmark <directorio_salida> <aridad>\n"
              << "  externalsort arity-search <entrada.bin> <min_a> <max_a> [cantidad]\n"
              << "  externalsort verify <archivo.bin> [cantidad]\n";
}

/**
 * @brief Convierte un texto a entero sin signo.
 */
static std::size_t to_size_t(const std::string &s) {
    return static_cast<std::size_t>(std::stoull(s));
}

/**
 * @brief Punto de entrada del programa.
 */
int main(int argc, char **argv) {
    try {
        if (argc < 2) {
            print_usage();
            return 1;
        }

        const std::string cmd = argv[1];
        SortConfig cfg;

        if (cmd == "generate") {
            if (argc < 4) {
                print_usage();
                return 1;
            }
            const std::string path = argv[2];
            const std::size_t count = to_size_t(argv[3]);
            const std::uint64_t seed = (argc >= 5) ? std::stoull(argv[4]) : cfg.seed;
            generate_random_file(path, count, seed, cfg);
            return 0;
        }

        if (cmd == "mergesort") {
            if (argc < 5) {
                print_usage();
                return 1;
            }
            const std::string input = argv[2];
            const std::string output = argv[3];
            const std::size_t arity = to_size_t(argv[4]);
            const std::size_t count = (argc >= 6) ? to_size_t(argv[5]) : resolve_count(input);
            DiskStats stats;
            external_mergesort(input, output, count, arity, cfg, &stats);
            std::cerr << "reads=" << stats.reads << " writes=" << stats.writes
                      << " accesses=" << (stats.reads + stats.writes) << '\n';
            return 0;
        }

        if (cmd == "quicksort") {
            if (argc < 5) {
                print_usage();
                return 1;
            }
            const std::string input = argv[2];
            const std::string output = argv[3];
            const std::size_t arity = to_size_t(argv[4]);
            const std::size_t count = (argc >= 6) ? to_size_t(argv[5]) : resolve_count(input);
            DiskStats stats;
            std::mt19937_64 rng(cfg.seed);
            external_quicksort(input, output, count, arity, cfg, &stats, rng);
            std::cerr << "reads=" << stats.reads << " writes=" << stats.writes
                      << " accesses=" << (stats.reads + stats.writes) << '\n';
            return 0;
        }

        if (cmd == "benchmark") {
            if (argc < 4) {
                print_usage();
                return 1;
            }
            const std::string outdir = argv[2];
            const std::size_t arity = to_size_t(argv[3]);
            run_benchmark(outdir, arity, cfg);
            return 0;
        }

        if (cmd == "arity-search") {
            if (argc < 5) {
                print_usage();
                return 1;
            }
            const std::string input = argv[2];
            const std::size_t min_a = to_size_t(argv[3]);
            const std::size_t max_a = to_size_t(argv[4]);
            const std::size_t count = (argc >= 6) ? to_size_t(argv[5]) : resolve_count(input);
            std::size_t best = search_best_arity(input, count, min_a, max_a, cfg);
            std::cout << best << '\n';
            return 0;
        }

        if (cmd == "verify") {
            if (argc < 3) {
                print_usage();
                return 1;
            }
            const std::string input = argv[2];
            const std::size_t count = (argc >= 4) ? to_size_t(argv[3]) : resolve_count(input);
            bool ok = is_sorted_file(input, count, cfg, nullptr);
            std::cout << (ok ? "sorted\n" : "not-sorted\n");
            return ok ? 0 : 2;
        }

        print_usage();
        return 1;
    } catch (const std::exception &e) {
        std::cerr << "Error: " << e.what() << '\n';
        return 1;
    }
}

