/**
 * @brief Copia un archivo lógico a otro respetando el tamaño dado.
 */
static void copy_file(const std::string &in, std::size_t count, const std::string &out,
                      const SortConfig &cfg, DiskStats *stats) {
    BlockReader reader(in, count, cfg, stats);
    BlockWriter writer(out, cfg, stats);
    i64 value;
    while (reader.next(value)) {
        writer.push(value);
    }
    writer.close();
    write_count_sidecar(out, count);
}
